        const maxDigit = Math.max(...digitsPresent);
        for (let k = 1; k <= maxDigit; k++) {
            if (!count[k] || count[k] !== k) return false;
        }

        return true;
    }

    let candidate = n + 1;
    while (true) {
        if (isSpecial(candidate)) {
            return candidate;
